 63→    private val autocryptStatusInteractor: AutocryptStatusInteractor,
 64→    private val replyToParser: ReplyToParser,
 65→    private val draftStateHeaderParser: AutocryptDraftStateHeaderParser,
 66→) {
 67→    private lateinit var account: Account
 68→    private var alwaysBccAddresses: Array<Address>? = null
 69→    private var hasContactPicker: Boolean? = null
