 93→    private val openPgpCallback = object : OpenPgpApiManagerCallback {
 94→        override fun onOpenPgpProviderStatusChanged() {
 95→            if (openPgpApiManager.openPgpProviderState == OpenPgpProviderState.UI_REQUIRED) {
 96→                recipientMvpView.showErrorOpenPgpUserInteractionRequired()
 97→            }
 98→            asyncUpdateCryptoStatus()
