146→    fun initFromReplyToMessage(message: Message?, isReplyAll: Boolean) {
147→        val replyToAddresses = if (isReplyAll) {
148→            replyToParser.getRecipientsToReplyAllTo(message, account)
149→        } else {
150→            replyToParser.getRecipientsToReplyTo(message, account)
151→        }
152→
153→        addToAddresses(*replyToAddresses.to)
154→        addCcAddresses(*replyToAddresses.cc)
155→
156→        val shouldSendAsPgpInline = composePgpInlineDecider.shouldReplyInline(message)
157→        if (shouldSendAsPgpInline) {
158→            isForceTextMessageFormat = true
159→        }
