275→    private fun addAlwaysBcc() {
276→        val alwaysBccAddresses = Address.parse(account.alwaysBcc)
277→        this.alwaysBccAddresses = alwaysBccAddresses
278→        if (alwaysBccAddresses.isEmpty()) return
279→
280→        object : RecipientLoader(context, account.openPgpProvider, *alwaysBccAddresses) {
281→            override fun deliverResult(result: List<Recipient>?) {
282→                val recipientArray = result!!.toTypedArray()
283→                recipientMvpView.silentlyAddBccAddresses(*recipientArray)
284→
285→                stopLoading()
286→                abandon()
287→            }
288→        }.startLoading()
289→    }
