297→    fun onPrepareOptionsMenu(menu: Menu) {
298→        val currentCryptoStatus = currentCachedCryptoStatus
299→
300→        if (currentCryptoStatus != null && currentCryptoStatus.isProviderStateOk()) {
301→            val isEncrypting = currentCryptoStatus.isEncryptionEnabled
