389→    fun asyncUpdateCryptoStatus() {
390→        currentCachedCryptoStatus = null
391→
392→        val openPgpProviderState = openPgpApiManager.openPgpProviderState
393→        var accountCryptoKey: Long? = account.openPgpKey
394→        if (accountCryptoKey == Account.NO_OPENPGP_KEY) {
395→            accountCryptoKey = null
396→        }
397→
398→        val composeCryptoStatus = ComposeCryptoStatus(
399→            openPgpProviderState = openPgpProviderState,
400→            openPgpKeyId = accountCryptoKey,
401→            recipientAddresses = allRecipients,
402→            isPgpInlineModeEnabled = isForceTextMessageFormat,
403→            isSenderPreferEncryptMutual = account.autocryptPreferEncryptMutual,
404→            isReplyToEncrypted = isReplyToEncryptedMessage,
405→            isEncryptAllDrafts = account.isOpenPgpEncryptAllDrafts,
406→            isEncryptSubject = account.isOpenPgpEncryptSubject,
407→            cryptoMode = currentCryptoMode,
408→        )
409→
410→        if (openPgpProviderState != OpenPgpProviderState.OK) {
411→            currentCachedCryptoStatus = composeCryptoStatus
412→            redrawCachedCryptoStatusIcon()
413→            return
414→        }
415→
416→        val recipientAddresses = composeCryptoStatus.recipientAddressesAsArray
417→        object : AsyncTask<Void?, Void?, RecipientAutocryptStatus?>() {
418→            override fun doInBackground(vararg params: Void?): RecipientAutocryptStatus? {
419→                val openPgpApi = openPgpApiManager.openPgpApi ?: return null
420→                return autocryptStatusInteractor.retrieveCryptoProviderRecipientStatus(openPgpApi, recipientAddresses)
421→            }
422→
423→            override fun onPostExecute(recipientAutocryptStatus: RecipientAutocryptStatus?) {
424→                currentCachedCryptoStatus = if (recipientAutocryptStatus != null) {
425→                    composeCryptoStatus.withRecipientAutocryptStatus(recipientAutocryptStatus)
426→                } else {
427→                    composeCryptoStatus
428→                }
429→
430→                redrawCachedCryptoStatusIcon()
431→            }
432→        }.execute()
433→    }
