760→        private void writeObject(ObjectOutputStream oos) throws IOException {
761→            oos.defaultWriteObject();
762→
763→            // custom serialization, Android's Uri class is not serializable
764→            if (photoThumbnailUri != null) {
765→                oos.writeInt(1);
766→                oos.writeUTF(photoThumbnailUri.toString());
767→            } else {
768→                oos.writeInt(0);
769→            }
770→        }
