772→        private void readObject(ObjectInputStream ois) throws ClassNotFoundException, IOException {
773→            ois.defaultReadObject();
774→
775→            // custom deserialization, Android's Uri class is not serializable
776→            if (ois.readInt() != 0) {
777→                String uriString = ois.readUTF();
778→                photoThumbnailUri = Uri.parse(uriString);
779→            }
780→        }
