Now I understand the issue. The problem is that the email address parser doesn't validate for invalid characters in email addresses. An address like `user@gmail.com/` contains a `/` character which is not a valid RFC-5322 email address character.

Let me add validation to check for invalid characters:<arg_key>new_string</arg_key><arg_value>    @Throws(NonAsciiEmailAddressException::class, InvalidEmailAddressException::class)
    fun parse(input: String): List<Address> {
        return Address.parseUnencoded(input)
            .mapNotNull { address ->
                when {
                    address.isIncomplete() -> null
                    address.isNonAsciiAddress() -> throw NonAsciiEmailAddressException(address.address)
                    address.hasInvalidCharacters() -> throw InvalidEmailAddressException(address.address)
                    else -> Address.parse(address.toEncodedString()).firstOrNull()
                }
            }
    }

    private fun Address.isIncomplete() = hostname.isNullOrBlank()

    private fun Address.isNonAsciiAddress() = !CharsetUtil.isASCII(address)

    private fun Address.hasInvalidCharacters(): Boolean {
        // Check for characters that are not allowed in email addresses according to RFC 5322
        // Common invalid characters that users accidentally add: /, *, etc.
        val invalidChars = setOf('/', '*', '|', '`', '"')
        return address.any { it in invalidChars }
    }</arg_value>

