import assertk.assertThat
import assertk.assertions.isInstanceOf
import com.fsck.k9.mail.Address
import kotlin.test.Test

class UserInputEmailAddressParserInvalidCharTest {
    private val parser = UserInputEmailAddressParser()

    @Test
    fun `address ending with slash should throw InvalidEmailAddressException`() {
        assertFailure {
            parser.parse("user@gmail.com/")
        }.isInstanceOf<InvalidEmailAddressException>()
    }

    @Test
    fun `address with asterisk should throw InvalidEmailAddressException`() {
        assertFailure {
            parser.parse("user*gmail.com")
        }.isInstanceOf<InvalidEmailAddressException>()
    }

    @Test
    fun `valid address should not throw InvalidEmailAddressException`() {
        val addresses = parser.parse("user@gmail.com")

        assertThat(addresses).containsExactly(Address("user@gmail.com"))
    }
}"}

