540→
541→        RecipientTokenSpan[] recipientSpans = text.getSpans(0, text.length(), RecipientTokenSpan.class);
542→        for (RecipientTokenSpan recipientSpan : recipientSpans) {
543→            if (recipientSpan.getToken().equals(currentRecipient)) {
