{"file_path":"/project/legacy/ui/legacy/src/test/java/com/fsck/k9/view/UserInputEmailAddressParserInvalidCharTest.kt","content":"package com.fsck.k9.view

import assertk.assertFailure
import assertk.assertThat
import assertk.assertions.isEmpty
import assertk.assertions.isInstanceOf
import com.fsck.k9.mail.Address
import kotlin.test.Test

class UserInputEmailAddressParserInvalidCharTest {
    private val parser = UserInputEmailAddressParser()

    @Test
    fun `invalid address ending with slash should throw InvalidEmailAddressException`() {
        assertFailure {
            parser.parse("user@gmail.com/")
        }.isInstanceOf<InvalidEmailAddressException>()
    }

    @Test
    fun `address with asterisk should throw InvalidEmailAddressException`() {
        assertFailure {
            parser.parse("user*gmail.com")
        }.isInstanceOf<InvalidEmailAddressException>()
    }

    @Test
    fun `address with pipe should throw InvalidEmailAddressException`() {
        assertFailure {
            parser.parse("user|gmail.com")
        }.isInstanceOf<InvalidEmailAddressException>()
    }

    @Test
    fun `address with backtick should throw InvalidEmailAddressException`() {
        assertFailure {
            parser.parse("user`gmail.com")
        }.isInstanceOf<InvalidEmailAddressException>()
    }

    @Test
    fun `address with quote should throw InvalidEmailAddressException`() {
        assertFailure {
            parser.parse("user\"gmail.com")
        }.isInstanceOf<InvalidEmailAddressException>()
    }

    @Test
    fun `valid email address should not throw exception`() {
        val addresses = parser.parse("user@gmail.com")
        assertThat(addresses).containsExactly(Address("user@gmail.com"))
    }

    @Test
    fun `incomplete address should return empty list`() {
        val addresses = parser.parse("user")
        assertThat(addresses).isEmpty()
    }

    @Test
    fun `address ending in at symbol should return empty list`() {
        val addresses = parser.parse("user@")
        assertThat(addresses).isEmpty()
    }

    @Test
    fun `address with non-ASCII characters should throw NonAsciiEmailAddressException`() {
        assertFailure {
            parser.parse("müller@domain.example")
        }.isInstanceOf<NonAsciiEmailAddressException>()
    }
}"}
